import{_ as r,c as a,o as i,a1 as l}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Политика конфиденциальности: Защита данных | OpenCodeDocs","description":"Узнайте о политике конфиденциальности и мерах защиты данных OpenCodeDocs. Как мы собираем, используем и храним вашу личную информацию и какими правами вы обладаете.","frontmatter":{"title":"Политика конфиденциальности: Защита данных | OpenCodeDocs","sidebarTitle":"Куда уходят ваши данные","subtitle":"Политика конфиденциальности: Защита данных","description":"Узнайте о политике конфиденциальности и мерах защиты данных OpenCodeDocs. Как мы собираем, используем и храним вашу личную информацию и какими правами вы обладаете."},"headers":[],"relativePath":"ru/privacy.md","filePath":"ru/privacy.md"}'),t={name:"ru/privacy.md"};function e(n,o,s,g,c,h){return i(),a("div",null,[...o[0]||(o[0]=[l('<h1 id="политика-конфиденциальности" tabindex="-1">Политика конфиденциальности <a class="header-anchor" href="#политика-конфиденциальности" aria-label="Permalink to &quot;Политика конфиденциальности&quot;">​</a></h1><p>Дата последнего обновления: 2026-01-01</p><p>Спасибо, что пользуетесь OpenCodeDocs. Мы придаем большое значение защите вашей конфиденциальности и личной информации. Данная политика конфиденциальности поможет вам понять, как мы собираем, используем, храним и защищаем вашу личную информацию.</p><h2 id="_1-информация-которую-мы-собираем" tabindex="-1">1. Информация, которую мы собираем <a class="header-anchor" href="#_1-информация-которую-мы-собираем" aria-label="Permalink to &quot;1. Информация, которую мы собираем&quot;">​</a></h2><p>При использовании услуг OpenCodeDocs мы можем собирать следующие типы информации:</p><h3 id="информация-об-аккаунте" tabindex="-1">Информация об аккаунте <a class="header-anchor" href="#информация-об-аккаунте" aria-label="Permalink to &quot;Информация об аккаунте&quot;">​</a></h3><ul><li><strong>Адрес электронной почты</strong>: используется для регистрации аккаунта, проверки входа и важных уведомлений</li><li><strong>Имя пользователя</strong>: выбранное вами отображаемое имя</li><li><strong>Информация об аккаунте GitHub</strong>: если вы выберете вход через GitHub, мы получим вашу общедоступную информацию</li></ul><h3 id="данные-использования" tabindex="-1">Данные использования <a class="header-anchor" href="#данные-использования" aria-label="Permalink to &quot;Данные использования&quot;">​</a></h3><ul><li><strong>История просмотров</strong>: страницы руководств, которые вы посещали, и время посещения</li><li><strong>Интерактивные действия</strong>: копирование кода, переходы между разделами и другие операции</li><li><strong>История поиска</strong>: ключевые слова, которые вы искали на сайте</li></ul><h3 id="информация-об-устроистве" tabindex="-1">Информация об устройстве <a class="header-anchor" href="#информация-об-устроистве" aria-label="Permalink to &quot;Информация об устройстве&quot;">​</a></h3><ul><li><strong>Тип браузера</strong>: Chrome, Firefox, Safari и др.</li><li><strong>Операционная система</strong>: Windows, macOS, Linux и др.</li><li><strong>IP-адрес</strong>: используется для защиты безопасности и оптимизации по регионам</li></ul><h2 id="_2-способы-использования-информации" tabindex="-1">2. Способы использования информации <a class="header-anchor" href="#_2-способы-использования-информации" aria-label="Permalink to &quot;2. Способы использования информации&quot;">​</a></h2><p>Собранная нами информация будет использоваться для следующих целей:</p><ul><li><strong>Предоставление услуг</strong>: обеспечение нормального доступа и использования материалов руководств</li><li><strong>Персонализация опыта</strong>: запоминание вашего прогресса чтения и настроек предпочтений</li><li><strong>Улучшение продукта</strong>: анализ паттернов использования для оптимизации контента и функций</li><li><strong>Обеспечение безопасности</strong>: обнаружение аномального поведения, предотвращение злоупотреблений</li><li><strong>Отправка уведомлений</strong>: отправка напоминаний об обновлениях руководств и важных объявлений (можно отказаться от подписки)</li></ul><h2 id="_3-совместное-использование-и-раскрытие-информации" tabindex="-1">3. Совместное использование и раскрытие информации <a class="header-anchor" href="#_3-совместное-использование-и-раскрытие-информации" aria-label="Permalink to &quot;3. Совместное использование и раскрытие информации&quot;">​</a></h2><p>Мы не продаем вашу личную информацию. Совместное использование возможно только в следующих случаях:</p><ul><li><strong>Сторонние поставщики услуг</strong>: такие как Vercel (хостинг), Plausible (аналитика), они имеют доступ только к информации, необходимой для выполнения своих обязанностей</li><li><strong>Юридические требования</strong>: раскрытие в соответствии с законами и положениями или по требованию правительства</li><li><strong>Защита прав</strong>: в случаях, необходимых для защиты прав OpenCodeDocs и пользователей</li></ul><h2 id="_4-хранение-и-безопасность-данных" tabindex="-1">4. Хранение и безопасность данных <a class="header-anchor" href="#_4-хранение-и-безопасность-данных" aria-label="Permalink to &quot;4. Хранение и безопасность данных&quot;">​</a></h2><ul><li><strong>Место хранения</strong>: данные хранятся на безопасных серверах в США и Азиатско-Тихоокеанском регионе</li><li><strong>Меры шифрования</strong>: данные передаются с шифрованием TLS/SSL, чувствительные данные хранятся с шифрованием AES-256</li><li><strong>Контроль доступа</strong>: строго ограниченные права доступа внутреннего персонала к данным</li><li><strong>Срок хранения</strong>: после удаления аккаунта личные данные будут удалены в течение 30 дней</li></ul><h2 id="_5-ваши-права" tabindex="-1">5. Ваши права <a class="header-anchor" href="#_5-ваши-права" aria-label="Permalink to &quot;5. Ваши права&quot;">​</a></h2><p>Согласно «Закону о защите личной информации» и GDPR, вы обладаете следующими правами:</p><ul><li><strong>Право на доступ</strong>: вы имеете право просматривать личную информацию, которую мы храним о вас</li><li><strong>Право на исправление</strong>: вы имеете право требовать исправления неточной личной информации</li><li><strong>Право на удаление</strong>: вы имеете право требовать удаления вашей личной информации</li><li><strong>Право на экспорт</strong>: вы имеете право экспортировать свои данные в общем формате</li><li><strong>Право на отзыв согласия</strong>: вы имеете право в любой момент отозвать ранее предоставленное согласие</li></ul><p>Для осуществления вышеуказанных прав, пожалуйста, свяжитесь с нами через контактную информацию ниже.</p><h2 id="_6-политика-в-отношении-фаилов-cookie" tabindex="-1">6. Политика в отношении файлов cookie <a class="header-anchor" href="#_6-политика-в-отношении-фаилов-cookie" aria-label="Permalink to &quot;6. Политика в отношении файлов cookie&quot;">​</a></h2><p>Мы используем следующие типы файлов cookie:</p><ul><li><strong>Обязательные файлы cookie</strong>: поддержание состояния входа, запоминание языковых предпочтений</li><li><strong>Аналитические файлы cookie</strong>: статистика посещаемости и паттернов использования (используется уважающая конфиденциальность Plausible)</li><li><strong>Рекламные файлы cookie</strong>: <ul><li>Сторонние поставщики (включая Google) используют файлы cookie для показа рекламы на основе истории посещений пользователя на вашем сайте или других сайтах.</li><li>Google использует рекламные файлы cookie, чтобы позволить ему и его партнерам показывать рекламу пользователям на основе истории посещения вашего сайта и/или других сайтов в Интернете.</li><li>Пользователи могут посетить <a href="https://www.google.com/settings/ads" target="_blank" rel="noreferrer">Google Ads Settings</a>, чтобы отключить персонализированную рекламу. Или вы можете направить пользователей на <a href="http://www.aboutads.info/choices/" target="_blank" rel="noreferrer">www.aboutads.info</a>, чтобы отключить файлы cookie сторонних поставщиков, используемые для персонализированной рекламы.</li></ul></li></ul><p>Вы можете управлять файлами cookie через настройки браузера. Отключение обязательных файлов cookie может повлиять на нормальное использование некоторых функций.</p><h2 id="_7-свяжитесь-с-нами" tabindex="-1">7. Свяжитесь с нами <a class="header-anchor" href="#_7-свяжитесь-с-нами" aria-label="Permalink to &quot;7. Свяжитесь с нами&quot;">​</a></h2><p>Если у вас есть какие-либо вопросы по данной политике конфиденциальности или вам необходимо осуществить свои права в отношении данных, пожалуйста, свяжитесь с нами:</p><ul><li><strong>Электронная почта</strong>: <a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>Время ответа</strong>: мы ответим на ваш запрос в течение 15 рабочих дней</li></ul>',30)])])}const p=r(t,[["render",e]]);export{u as __pageData,p as default};
